mapper.sql:
WHERE user_space.id is not null
AND user_space.deleted = #{deleted}
AND user_space.user_id = #{reqUserId}

AND user_space.status = #{status}
AND user_space.status IN ('ACTIVE', 'PENDING')
AND user_space.role = #{role}
AND space.group_id = #{groupId}

mapper.select:
SELECT user_space.id FROM user_space LEFT JOIN space ON user_space.space_id = space.id LEFT JOIN tb_group ON space.group_id = tb_group.id
AND space.deleted = false
AND #{cursor} > user_space.id AND user_space.id > #{cursor}
ORDER BY user_space.id DESC ASC
LIMIT 0, #{perPage}

SELECT COUNT(*) > 0
FROM user_space us
         JOIN space s ON us.space_id = s.id
WHERE us.user_id = #{userId}
  AND s.group_id = #{groupId}
  AND us.role = 'ADMIN'

SELECT COUNT(*) > 0
FROM user_space
WHERE user_id = #{userId}
  AND space_id = #{spaceId}
  AND status = 'ACTIVE'
